function toAccount(row) {
  return {
    accountId: row.account_id,
    name:      row.name,
    tier:      row.tier,
    status:    row.status,
    createdAt: row.created_at,
  };
}

export async function createAccounts(client, data) {
  const { accountId, name, tier, status } = data;
  const { rows } = await client.query(
    `INSERT INTO accounts (account_id, name, tier, status)
     VALUES ($1, $2, $3, $4)
     RETURNING *`,
    [accountId, name, tier, status]
  );
  return toAccount(rows[0]);
}

export async function getAccounts(client, accountId) {
  const { rows } = await client.query(
    'SELECT * FROM accounts WHERE account_id = $1',
    [accountId]
  );
  return rows[0] ? toAccount(rows[0]) : null;
}

export async function updateAccounts(client, accountId, updates) {
  const colMap = { name: 'name', tier: 'tier', status: 'status', createdAt: 'created_at' };
  const fields = Object.keys(updates);
  const setClauses = fields.map((f, i) => `${colMap[f]} = $${i + 2}`).join(', ');
  const { rows } = await client.query(
    `UPDATE accounts SET ${setClauses} WHERE account_id = $1 RETURNING *`,
    [accountId, ...fields.map(f => updates[f])]
  );
  return rows[0] ? toAccount(rows[0]) : null;
}

export async function deleteAccounts(client, accountId) {
  const { rowCount } = await client.query(
    'DELETE FROM accounts WHERE account_id = $1',
    [accountId]
  );
  return rowCount > 0;
}
